#include <iostream>
#include <vector>
using namespace std;

void bf(const string &s){
  int bkt=0;
  for(int i=0;i<s.size();++i){
    if(s[i]=='[')++bkt;
    if(s[i]==']')--bkt;
    if(bkt<0)return;
  }
  vector<int> memory(30000);
  int ptr=0;
  for(int i=0;i<s.size();++i){
    if(s[i]=='+'){
      memory[ptr]=(memory[ptr]+1)&0xff;
    }
    if(s[i]=='-'){
      memory[ptr]=(memory[ptr]-1+0x100)&0xff;
    }
    if(s[i]=='<'){
      --ptr;
      if(ptr<0)return;
    }
    if(s[i]=='>'){
      ++ptr;
      if(ptr>=memory.size())memory.reserve(memory.size()+memory.size()/2);
    }
    if(s[i]=='['){
      if(!memory[ptr]){
        for(int j=i+1;j<s.size();++j) if(s[j]==']'){i=j-1;break;}
      }
    }
    if(s[i]==']'){
      if(memory[ptr]){
        for(int j=i-1;j>=0;--j) if(s[j]=='['){i=j;break;}
      }
    }
    if(s[i]=='.'){
      cout<<(char)memory[ptr];
    }
  }
}
